import{_ as e,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"更新履歴: バージョン履歴 | everything-claude-code","description":"everything-claude-code のバージョン履歴と重要な変更点を確認。新機能、セキュリティ修正、ドキュメント更新を追跡し、アップグレードの必要性を判断できます。","frontmatter":{"title":"更新履歴: バージョン履歴 | everything-claude-code","sidebarTitle":"最新の更新を確認","subtitle":"更新履歴: バージョン履歴","description":"everything-claude-code のバージョン履歴と重要な変更点を確認。新機能、セキュリティ修正、ドキュメント更新を追跡し、アップグレードの必要性を判断できます。","tags":["changelog","updates"],"prerequisite":[],"order":250},"headers":[],"relativePath":"ja/affaan-m/everything-claude-code/changelog/release-notes/index.md","filePath":"ja/affaan-m/everything-claude-code/changelog/release-notes/index.md"}'),l={name:"ja/affaan-m/everything-claude-code/changelog/release-notes/index.md"};function r(d,a,n,s,h,c){return i(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="更新履歴-バージョン履歴と変更点" tabindex="-1">更新履歴：バージョン履歴と変更点 <a class="header-anchor" href="#更新履歴-バージョン履歴と変更点" aria-label="Permalink to &quot;更新履歴：バージョン履歴と変更点&quot;">​</a></h1><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>各バージョンの重要な変更点を把握する</li><li>新機能と修正内容を追跡する</li><li>アップグレードの必要性を判断する</li></ul><h2 id="バージョン履歴" tabindex="-1">バージョン履歴 <a class="header-anchor" href="#バージョン履歴" aria-label="Permalink to &quot;バージョン履歴&quot;">​</a></h2><h3 id="_2026-01-24-セキュリティ修正とドキュメント修正" tabindex="-1">2026-01-24 - セキュリティ修正とドキュメント修正 <a class="header-anchor" href="#_2026-01-24-セキュリティ修正とドキュメント修正" aria-label="Permalink to &quot;2026-01-24 - セキュリティ修正とドキュメント修正&quot;">​</a></h3><p><strong>修正内容</strong>：</p><ul><li>🔒 <strong>セキュリティ修正</strong>：<code>commandExists()</code> におけるコマンドインジェクション脆弱性を防止 <ul><li><code>execSync</code> を <code>spawnSync</code> に置き換え</li><li>入力を英数字、ハイフン、アンダースコア、ドットのみに制限</li></ul></li><li>📝 <strong>ドキュメント修正</strong>：<code>runCommand()</code> にセキュリティ警告を追加</li><li>🐛 <strong>XSS スキャナー誤検知修正</strong>：<code>&lt;script&gt;</code> と <code>&lt;binary&gt;</code> を <code>[script-name]</code> と <code>[binary-name]</code> に置換</li><li>📚 <strong>ドキュメント修正</strong>：<code>doc-updater.md</code> の <code>npx ts-morph</code> を正しい <code>npx tsx scripts/codemaps/generate.ts</code> に修正</li></ul><p><strong>影響</strong>：#42, #43, #51</p><hr><h3 id="_2026-01-22-クロスプラットフォーム対応とプラグイン化" tabindex="-1">2026-01-22 - クロスプラットフォーム対応とプラグイン化 <a class="header-anchor" href="#_2026-01-22-クロスプラットフォーム対応とプラグイン化" aria-label="Permalink to &quot;2026-01-22 - クロスプラットフォーム対応とプラグイン化&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li>🌐 <strong>クロスプラットフォーム対応</strong>：すべての hooks とスクリプトを Node.js で書き直し、Windows、macOS、Linux をサポート</li><li>📦 <strong>プラグインパッケージ化</strong>：Claude Code プラグインとして配布、プラグインマーケットプレイスからインストール可能</li><li>🎯 <strong>パッケージマネージャー自動検出</strong>：6 種類の検出優先順位をサポート <ul><li>環境変数 <code>CLAUDE_PACKAGE_MANAGER</code></li><li>プロジェクト設定 <code>.claude/package-manager.json</code></li><li><code>package.json</code> の <code>packageManager</code> フィールド</li><li>Lock ファイル検出（package-lock.json, yarn.lock, pnpm-lock.yaml, bun.lockb）</li><li>グローバル設定 <code>~/.claude/package-manager.json</code></li><li>最初に利用可能なパッケージマネージャーにフォールバック</li></ul></li></ul><p><strong>修正内容</strong>：</p><ul><li>🔄 <strong>Hook 読み込み</strong>：規約に基づいて hooks を自動読み込み、<code>plugin.json</code> での hooks 宣言を削除</li><li>📌 <strong>Hook パス</strong>：<code>${CLAUDE_PLUGIN_ROOT}</code> と相対パスを使用</li><li>🎨 <strong>UI 改善</strong>：スター履歴グラフとバッジバーを追加</li><li>📖 <strong>Hook 整理</strong>：session-end hooks を Stop から SessionEnd に移動</li></ul><hr><h3 id="_2026-01-20-機能強化" tabindex="-1">2026-01-20 - 機能強化 <a class="header-anchor" href="#_2026-01-20-機能強化" aria-label="Permalink to &quot;2026-01-20 - 機能強化&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li>💾 <strong>Memory Persistence Hooks</strong>：セッション間で自動的にコンテキストを保存・読み込み</li><li>🧠 <strong>Strategic Compact Hook</strong>：インテリジェントなコンテキスト圧縮提案</li><li>📚 <strong>Continuous Learning Skill</strong>：セッションから再利用可能なパターンを自動抽出</li><li>🎯 <strong>Strategic Compact Skill</strong>：トークン最適化戦略</li></ul><hr><h3 id="_2026-01-17-初回リリース" tabindex="-1">2026-01-17 - 初回リリース <a class="header-anchor" href="#_2026-01-17-初回リリース" aria-label="Permalink to &quot;2026-01-17 - 初回リリース&quot;">​</a></h3><p><strong>初期機能</strong>：</p><ul><li>✨ 完全な Claude Code 設定コレクション</li><li>🤖 9 つの専門化エージェント</li><li>⚡ 14 のスラッシュコマンド</li><li>📋 8 セットのルールセット</li><li>🔄 自動化 hooks</li><li>🎨 11 のスキルライブラリ</li><li>🌐 15 以上の MCP サーバー事前設定</li><li>📖 完全な README ドキュメント</li></ul><hr><h2 id="バージョン命名規則" tabindex="-1">バージョン命名規則 <a class="header-anchor" href="#バージョン命名規則" aria-label="Permalink to &quot;バージョン命名規則&quot;">​</a></h2><p>本プロジェクトでは従来のセマンティックバージョニングではなく、<strong>日付バージョン</strong>形式（<code>YYYY-MM-DD</code>）を採用しています。</p><h3 id="バージョンタイプ" tabindex="-1">バージョンタイプ <a class="header-anchor" href="#バージョンタイプ" aria-label="Permalink to &quot;バージョンタイプ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>タイプ</th><th>説明</th><th>例</th></tr></thead><tbody><tr><td><strong>新機能</strong></td><td>新機能または大幅な改善の追加</td><td><code>feat: add new agent</code></td></tr><tr><td><strong>修正</strong></td><td>バグや問題の修正</td><td><code>fix: resolve hook loading issue</code></td></tr><tr><td><strong>ドキュメント</strong></td><td>ドキュメントの更新</td><td><code>docs: update README</code></td></tr><tr><td><strong>スタイル</strong></td><td>フォーマットやコードスタイル</td><td><code>style: fix indentation</code></td></tr><tr><td><strong>リファクタリング</strong></td><td>コードのリファクタリング</td><td><code>refactor: simplify hook logic</code></td></tr><tr><td><strong>パフォーマンス</strong></td><td>パフォーマンス最適化</td><td><code>perf: improve context loading</code></td></tr><tr><td><strong>テスト</strong></td><td>テスト関連</td><td><code>test: add unit tests</code></td></tr><tr><td><strong>ビルド</strong></td><td>ビルドシステムや依存関係</td><td><code>build: update package.json</code></td></tr><tr><td><strong>リバート</strong></td><td>以前のコミットの取り消し</td><td><code>revert: remove version field</code></td></tr></tbody></table><hr><h2 id="更新の取得方法" tabindex="-1">更新の取得方法 <a class="header-anchor" href="#更新の取得方法" aria-label="Permalink to &quot;更新の取得方法&quot;">​</a></h2><h3 id="プラグインマーケットプレイスからの更新" tabindex="-1">プラグインマーケットプレイスからの更新 <a class="header-anchor" href="#プラグインマーケットプレイスからの更新" aria-label="Permalink to &quot;プラグインマーケットプレイスからの更新&quot;">​</a></h3><p>プラグインマーケットプレイスから Everything Claude Code をインストールした場合：</p><ol><li>Claude Code を開く</li><li><code>/plugin update everything-claude-code</code> を実行</li><li>更新完了を待つ</li></ol><h3 id="手動更新" tabindex="-1">手動更新 <a class="header-anchor" href="#手動更新" aria-label="Permalink to &quot;手動更新&quot;">​</a></h3><p>リポジトリを手動でクローンした場合：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/plugins/everything-claude-code</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="マーケットプレイスからのインストール" tabindex="-1">マーケットプレイスからのインストール <a class="header-anchor" href="#マーケットプレイスからのインストール" aria-label="Permalink to &quot;マーケットプレイスからのインストール&quot;">​</a></h3><p>初回インストール：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> affaan-m/everything-claude-code</span></span></code></pre></div><hr><h2 id="変更影響分析" tabindex="-1">変更影響分析 <a class="header-anchor" href="#変更影響分析" aria-label="Permalink to &quot;変更影響分析&quot;">​</a></h2><h3 id="セキュリティ修正-アップグレード必須" tabindex="-1">セキュリティ修正（アップグレード必須） <a class="header-anchor" href="#セキュリティ修正-アップグレード必須" aria-label="Permalink to &quot;セキュリティ修正（アップグレード必須）&quot;">​</a></h3><ul><li><strong>2026-01-24</strong>：コマンドインジェクション脆弱性の修正、アップグレードを強く推奨</li></ul><h3 id="機能強化-任意のアップグレード" tabindex="-1">機能強化（任意のアップグレード） <a class="header-anchor" href="#機能強化-任意のアップグレード" aria-label="Permalink to &quot;機能強化（任意のアップグレード）&quot;">​</a></h3><ul><li><strong>2026-01-22</strong>：クロスプラットフォーム対応、Windows ユーザーはアップグレード必須</li><li><strong>2026-01-20</strong>：新機能強化、必要に応じてアップグレード</li></ul><h3 id="ドキュメント更新-アップグレード不要" tabindex="-1">ドキュメント更新（アップグレード不要） <a class="header-anchor" href="#ドキュメント更新-アップグレード不要" aria-label="Permalink to &quot;ドキュメント更新（アップグレード不要）&quot;">​</a></h3><ul><li>ドキュメント更新は機能に影響しません。README を手動で確認できます</li></ul><hr><h2 id="既知の問題" tabindex="-1">既知の問題 <a class="header-anchor" href="#既知の問題" aria-label="Permalink to &quot;既知の問題&quot;">​</a></h2><h3 id="現在のバージョン-2026-01-24" tabindex="-1">現在のバージョン（2026-01-24） <a class="header-anchor" href="#現在のバージョン-2026-01-24" aria-label="Permalink to &quot;現在のバージョン（2026-01-24）&quot;">​</a></h3><ul><li>既知の重大な問題はありません</li></ul><h3 id="以前のバージョン" tabindex="-1">以前のバージョン <a class="header-anchor" href="#以前のバージョン" aria-label="Permalink to &quot;以前のバージョン&quot;">​</a></h3><ul><li>2026-01-22 以前：Hooks の読み込みに手動設定が必要（2026-01-22 で修正済み）</li><li>2026-01-20 以前：Windows 非対応（2026-01-22 で修正済み）</li></ul><hr><h2 id="貢献とフィードバック" tabindex="-1">貢献とフィードバック <a class="header-anchor" href="#貢献とフィードバック" aria-label="Permalink to &quot;貢献とフィードバック&quot;">​</a></h2><h3 id="問題の報告" tabindex="-1">問題の報告 <a class="header-anchor" href="#問題の報告" aria-label="Permalink to &quot;問題の報告&quot;">​</a></h3><p>バグを発見した場合や機能の提案がある場合：</p><ol><li><a href="https://github.com/affaan-m/everything-claude-code/issues" target="_blank" rel="noreferrer">GitHub Issues</a> で類似の問題がないか検索</li><li>ない場合は、新しい Issue を作成し、以下を記載： <ul><li>バージョン情報</li><li>オペレーティングシステム</li><li>再現手順</li><li>期待される動作 vs 実際の動作</li></ul></li></ol><h3 id="pr-の提出" tabindex="-1">PR の提出 <a class="header-anchor" href="#pr-の提出" aria-label="Permalink to &quot;PR の提出&quot;">​</a></h3><p>貢献を歓迎します！詳細は <a href="https://github.com/affaan-m/everything-claude-code/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> をご覧ください。</p><hr><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Everything Claude Code は日付バージョン番号（<code>YYYY-MM-DD</code>）を使用</li><li>セキュリティ修正（2026-01-24 など）は必ずアップグレード</li><li>機能強化は必要に応じてアップグレード</li><li>プラグインマーケットプレイスユーザーは <code>/plugin update</code> で更新</li><li>手動インストールユーザーは <code>git pull</code> で更新</li><li>問題報告と PR 提出はプロジェクトガイドラインに従う</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../appendix/config-reference/">設定ファイル詳解</a></strong> を学びます。</p><p>学習内容：</p><ul><li><code>settings.json</code> の完全なフィールド説明</li><li>Hooks 設定の高度なオプション</li><li>MCP サーバー設定の詳細</li><li>カスタム設定のベストプラクティス</li></ul></blockquote>',64)])])}const p=e(l,[["render",r]]);export{u as __pageData,p as default};
